frappe.ui.form.on('Material Request', {
    refresh(frm) {
        // Get the logged in user's ID
        var logged_in_user_id = frappe.session.user;

        // Get the logged in user's department
        frappe.db.get_value('Employee', {'user_id': logged_in_user_id}, 'department', (r) => {
            if(r && r.department) {
                // Set the department in the form
                frm.doc.custom_department_originator = r.department;
                // Refresh the form to show the updated value
                frm.refresh_field('custom_department_originator');
            }
        });
    }
});

frappe.ui.form.on('Material Request', {
    refresh(frm) {
        // Calculate and update total on form refresh
        if (frm.doc.workflow_state === 'Draft') {
            updateTotalAmount(frm);
        }
        // frappe.msgprint (frm.doc.workflow_state);
    },
    // Triggered when the 'items' table is changed
    items: function(frm, cdt, cdn) {
        // Call your custom function here
        if (frm.doc.workflow_state === 'Draft') {
            updateTotalAmount(frm);
        }

    },

});

// Function to update total amount field
function updateTotalAmount(frm) {
    let total_amount = 0;
    // frappe.msgprint('You are only allowed Material Receipt');
    // Calculate total amount from line items
    frm.doc.items.forEach(item => {
        total_amount += (item.rate * item.qty);
    });
    // Update custom_document_total field with the calculated total amount
    frm.set_value('custom_document_total', total_amount);
    // Refresh form to reflect the changes
    frm.refresh_field('custom_document_total');
}

